const items = $input.all();

const CHECK_LABELS = {
  keine_preise:     'Aktive Slots ohne Preis',
  negative_qty:     'Negative Lagermengen',
  wf3_stale:        'WF3 Verkaufsworkflow haengt',
  alte_warnungen:   'Alte ungeloeste Warnungen (>7 Tage)',
  pending_proposals:'Offene Rechnungsvorschlaege (>14 Tage)',
};

const wf3Items   = items.filter(i => i.json.check_type === 'wf3_stale');
const otherItems = items.filter(i => i.json.check_type !== 'wf3_stale');
const hasWf3Stale    = wf3Items.length > 0;
const hasOtherIssues = otherItems.length > 0;
const hasIssues      = hasWf3Stale || hasOtherIssues;

if (!hasIssues) {
  return [{ json: {
    status: 'OK', count: 0, has_issues: false,
    restart_flag: 'NEIN',
    email_subject: null, email_body: null,
    summary: 'Alle DB-Konsistenzpruefungen bestanden.'
  }}];
}

const grouped = {};
for (const { json: row } of otherItems) {
  if (!grouped[row.check_type]) grouped[row.check_type] = [];
  grouped[row.check_type].push(row.message);
}

const otherLines = Object.entries(grouped).map(([type, msgs]) => {
  const label = CHECK_LABELS[type] || type;
  return '<h3 style="color:#c0392b">' + label + ' (' + msgs.length + ')</h3><ul>' +
    msgs.map(m => '<li>' + m + '</li>').join('') + '</ul>';
}).join('');

const wf3Section = hasWf3Stale
  ? '<h3 style="color:#e67e22">WF3 Verkaufsworkflow haengt — Auto-Neustart ausgeloest</h3><ul>' +
    wf3Items.map(i => '<li>' + i.json.message + '</li>').join('') + '</ul>'
  : '';

const ts = new Date().toISOString();
const totalCount = otherItems.length + (hasWf3Stale ? 1 : 0);

return [{ json: {
  status: 'FEHLER',
  count: totalCount,
  has_issues: hasIssues,
  restart_flag: hasWf3Stale ? 'JA' : 'NEIN',
  email_subject: '[DB-Check] ' + totalCount + ' Problem' + (totalCount !== 1 ? 'e' : '') + ' — Automatenlager',
  email_body: '<h2 style="color:#c0392b">DB-Konsistenzpruefung: ' + totalCount + ' Problem' +
    (totalCount !== 1 ? 'e' : '') + '</h2>' + wf3Section + otherLines +
    '<hr><p style="color:#888;font-size:12px">WF-Val Check: ' + ts + '</p>'
}}];

